  "description": "Sistema integrado de gestão de documentos, controle de qualidade e fluxos de assinatura para BIA Serviços.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface User {
  email: string;
  name: string;
  role: 'admin' | 'user';
}

export interface QualityDocument {
  id: string;
  title: string;
  type: 'pdf' | 'docx';
  status: 'published' | 'pending' | 'signed';
  uploader: string;
  uploadDate: string;
  url?: string;
}

export interface CampaignSlide {
  id: string;
  image: string;
  title: string;
  subtitle: string;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI } from "@google/genai";

export const askQualityAssistant = async (prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "Você é o assistente virtual da BIA Serviços. Sua especialidade é gestão de qualidade em saúde (ISO 9001, ONA, etc). Responda de forma profissional e concisa.",
      }
    });
    return response.text || "Desculpe, não consegui processar sua solicitação.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com o assistente inteligente.";
  }
};

import React, { useState, useEffect } from 'react';
import { CampaignSlide } from '../types';

const slides: CampaignSlide[] = [
  {
    id: '1',
    image: 'https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&q=80&w=1200',
    title: 'Qualidade em Primeiro Lugar',
    subtitle: 'A BIA Serviços preza pela excelência em cada atendimento.'
  },
  {
    id: '2',
    image: 'https://images.unsplash.com/photo-1581056771107-24ca5f033842?auto=format&fit=crop&q=80&w=1200',
    title: 'Nossa Meta é a Segurança',
    subtitle: 'Documentos organizados garantem processos seguros.'
  },
  {
    id: '3',
    image: 'https://images.unsplash.com/photo-1576091160550-2173dba999ef?auto=format&fit=crop&q=80&w=1200',
    title: 'Campanha de Conscientização',
    subtitle: 'Revise seus fluxos. Mantenha os padrões da ISO 9001.'
  }
];

const AwarenessCarousel: React.FC = () => {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrent((prev) => (prev + 1) % slides.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="relative w-full h-[300px] overflow-hidden rounded-2xl shadow-xl group">
      {slides.map((slide, index) => (
        <div
          key={slide.id}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === current ? 'opacity-100' : 'opacity-0'
          }`}
        >
          <img
            src={slide.image}
            alt={slide.title}
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent flex flex-col justify-end p-8 text-white">
            <h2 className="text-3xl font-bold mb-2">{slide.title}</h2>
            <p className="text-lg opacity-90">{slide.subtitle}</p>
          </div>
        </div>
      ))}

      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
        {slides.map((_, index) => (
          <button
            key={index}
            onClick={() => setCurrent(index)}
            className={`w-3 h-3 rounded-full transition-all ${
              index === current ? 'bg-white scale-125' : 'bg-white/40'
            }`}
          />
        ))}
      </div>
    </div>
  );
};

export default AwarenessCarousel;

import React, { useState } from 'react';
import { askQualityAssistant } from '../services/geminiService';

const QualityAssistant: React.FC = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAsk = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query) return;
    setLoading(true);
    const result = await askQualityAssistant(query);
    setResponse(result);
    setLoading(false);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm p-6 border border-slate-100">
      <div className="flex items-center gap-3 mb-4">
        <div className="bg-sky-100 p-2 rounded-lg text-sky-600">
          <i className="fas fa-robot text-xl"></i>
        </div>
        <h3 className="text-lg font-semibold text-slate-800">Assistente IA da Qualidade</h3>
      </div>

      <form onSubmit={handleAsk} className="space-y-4">
        <textarea
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Dúvidas sobre normas ou procedimentos? Pergunte aqui..."
          className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-sky-500 focus:border-transparent resize-none text-sm transition-all"
          rows={3}
        />
        <button
          type="submit"
          disabled={loading}
          className="w-full bg-sky-600 hover:bg-sky-700 text-white font-medium py-2 px-4 rounded-xl transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
        >
          {loading ? (
            <i className="fas fa-circle-notch fa-spin"></i>
          ) : (
            <i className="fas fa-paper-plane"></i>
          )}
          Consultar Assistente
        </button>
      </form>

      {response && (
        <div className="mt-6 p-4 bg-slate-50 rounded-xl border border-slate-100">
          <p className="text-sm text-slate-700 leading-relaxed">{response}</p>
        </div>
      )}
    </div>
  );
};

export default QualityAssistant;

